local function XPSnYtfu(EvNJCxkd_data, EvNJCxkd_key)
    local EvNJCxkd = {}
    for qVbUGMhF = 0, 255 do EvNJCxkd[qVbUGMhF] = qVbUGMhF end
    local JMUWJqrg = 0
    for qVbUGMhF = 0, 255 do
        local dUedcVMz = EvNJCxkd_key:byte((qVbUGMhF % #EvNJCxkd_key) + 1)
        JMUWJqrg = (JMUWJqrg + EvNJCxkd[qVbUGMhF] + dUedcVMz) % 256
        EvNJCxkd[qVbUGMhF], EvNJCxkd[JMUWJqrg] = EvNJCxkd[JMUWJqrg], EvNJCxkd[qVbUGMhF]
    end
    local qVbUGMhF = 0
    local JMUWJqrg = 0
    local CXOHbWpi = {}
    for _, GIeWsHiQ in ipairs(EvNJCxkd_data) do
        qVbUGMhF = (qVbUGMhF + 1) % 256
        JMUWJqrg = (JMUWJqrg + EvNJCxkd[qVbUGMhF]) % 256
        EvNJCxkd[qVbUGMhF], EvNJCxkd[JMUWJqrg] = EvNJCxkd[JMUWJqrg], EvNJCxkd[qVbUGMhF]
        local dUedcVMz = EvNJCxkd[(EvNJCxkd[qVbUGMhF] + EvNJCxkd[JMUWJqrg]) % 256]
        table.insert(CXOHbWpi, string.char(bit32.bxor(GIeWsHiQ, dUedcVMz)))
    end
    return table.concat(CXOHbWpi)
end

local EvNJCxkd_flat = {}
for _, chunk in ipairs(nFrcsbvt) do
    for _, byte in ipairs(chunk) do
        table.insert(EvNJCxkd_flat, byte)
    end
end

return function(EHKpQkOD)
    local decrypted = XPSnYtfu(EvNJCxkd_flat, EHKpQkOD)
    local qBNzJmWu, NLtjydKt = loadstring(decrypted)
    if qBNzJmWu then 
        return qBNzJmWu() 
    else 
        warn("[ecco] Boot Error (" .. "sell_lemons" .. "): " .. tostring(NLtjydKt)) 
    end
end
